        if (!has_switch) {
            for (auto& [v, w] : adj[u]) {
                long long new_cost = cost + 2 * w;
                if (new_cost < dist[v][false]) {
                    dist[v][false] = new_cost;
                    pq.push({new_cost, {v, false}});
                }
            }
        }
    }

    return -1;
}

